const event = $('LINE Webhook').first().json.body.events[0];
if (!event || !event.message) return [];
const source = event.source;
const sourceType = source.type;
const userId = source.userId || '';
const to = sourceType === 'group' ? (source.groupId || source.roomId) : userId;
const text = (event.message && event.message.text) || '';
// 只處理文字訊息；貼圖/圖片等略過
if (!text.trim()) return [];
// （選用）只允許特定群組才回答：解開下兩行並填 <LINE_GROUP_ID>
// const ALLOWED_GROUP = '<LINE_GROUP_ID>';
// if ((sourceType === 'group' || sourceType === 'room') && (source.groupId || source.roomId) !== ALLOWED_GROUP) return [];
return [{ json: { to, sessionId: userId || to, message: text.trim() } }];

const r = $json || {};
const ans = (r.answer || '').trim() || '抱歉，這個問題我在 SOP 文件裡查不到，建議直接詢問主管或補件 🙏';
const to = $('處理問題').first().json.to;
const TOKEN = '<LINE_CHANNEL_ACCESS_TOKEN>';
if (to) {
  await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.line.me/v2/bot/message/push',
    headers: { 'Authorization': `Bearer ${TOKEN}`, 'Content-Type': 'application/json' },
    body: { to, messages: [{ type: 'text', text: ans }] }
  });
}
return [{ json: { sent: true } }];
